package com.hospital.management.dao.impl;import com.hospital.management.dao.BedDao;import com.hospital.management.model.*;import com.hospital.management.util.DatabaseConnectionManager;import java.sql.*;import java.util.*;public class BedDaoImpl implements BedDao{private static final String S="SELECT b.*,r.ROOM_NUMBER,r.ROOM_TYPE,r.DAILY_RATE,a.ADMISSION_ID CURRENT_ADMISSION_ID,a.PATIENT_ID CURRENT_PATIENT_ID,p.FIRST_NAME||' '||p.LAST_NAME CURRENT_PATIENT_NAME FROM BEDS b JOIN ROOMS r ON r.ROOM_ID=b.ROOM_ID LEFT JOIN ADMISSIONS a ON a.BED_ID=b.BED_ID AND a.STATUS IN('ADMITTED','TRANSFERRED') LEFT JOIN PATIENTS p ON p.PATIENT_ID=a.PATIENT_ID ";public Optional<Bed>findById(Long id)throws SQLException{try(Connection c=DatabaseConnectionManager.getConnection()){return one(c,id,false);}}public Optional<Bed>lockById(Connection c,Long id)throws SQLException{return one(c,id,true);}private Optional<Bed>one(Connection c,Long id,boolean lock)throws SQLException{try(PreparedStatement s=c.prepareStatement(S+"WHERE b.BED_ID=?"+(lock?" FOR UPDATE OF b.STATUS":""))){s.setLong(1,id);try(ResultSet r=s.executeQuery()){return r.next()?Optional.of(map(r)):Optional.empty();}}}public Page<Bed>findAll(PageRequest p,Long room,String st)throws SQLException{String z=st==null||st.isBlank()?null:st.toUpperCase();try(Connection c=DatabaseConnectionManager.getConnection();PreparedStatement s=c.prepareStatement(S+"WHERE (? IS NULL OR b.ROOM_ID=?) AND (? IS NULL OR b.STATUS=?) AND (? IS NULL OR UPPER(r.ROOM_NUMBER||' '||b.BED_NUMBER||' '||b.STATUS) LIKE ?) ORDER BY r.ROOM_NUMBER,b.BED_NUMBER OFFSET ? ROWS FETCH NEXT ? ROWS ONLY")){int i=1;pair(s,i,room);i+=2;s.setString(i++,z);s.setString(i++,z);String q=p.getSearchTerm().isBlank()?null:"%"+p.getSearchTerm().toUpperCase()+"%";s.setString(i++,q);s.setString(i++,q);s.setInt(i++,p.getOffset());s.setInt(i,p.getPageSize());List<Bed>x=new ArrayList<>();try(ResultSet r=s.executeQuery()){while(r.next())x.add(map(r));}return new Page<>(x,p.getPageNumber(),p.getPageSize(),p.getOffset()+x.size());}}public List<Bed>findAvailableBeds(Long dep,String type)throws SQLException{String t=type==null||type.isBlank()?null:type.toUpperCase();try(Connection c=DatabaseConnectionManager.getConnection();PreparedStatement s=c.prepareStatement(S+"WHERE b.STATUS='AVAILABLE' AND r.STATUS='ACTIVE' AND (? IS NULL OR r.DEPARTMENT_ID=?) AND (? IS NULL OR r.ROOM_TYPE=?) ORDER BY r.ROOM_NUMBER,b.BED_NUMBER")){pair(s,1,dep);s.setString(3,t);s.setString(4,t);List<Bed>x=new ArrayList<>();try(ResultSet r=s.executeQuery()){while(r.next())x.add(map(r));}return x;}}public long create(Bed b)throws SQLException{try(Connection c=DatabaseConnectionManager.getConnection();PreparedStatement s=c.prepareStatement("INSERT INTO BEDS(ROOM_ID,BED_NUMBER,STATUS)VALUES(?,?,?)",new String[]{"BED_ID"})){s.setLong(1,b.getRoomId());s.setString(2,b.getBedNumber());s.setString(3,b.getStatus());s.executeUpdate();try(ResultSet r=s.getGeneratedKeys()){return r.next()?r.getLong(1):0;}}}public boolean update(Bed b)throws SQLException{try(Connection c=DatabaseConnectionManager.getConnection();PreparedStatement s=c.prepareStatement("UPDATE BEDS SET ROOM_ID=?,BED_NUMBER=?,STATUS=?,UPDATED_AT=CURRENT_TIMESTAMP WHERE BED_ID=? AND STATUS<>'OCCUPIED'")){s.setLong(1,b.getRoomId());s.setString(2,b.getBedNumber());s.setString(3,b.getStatus());s.setLong(4,b.getBedId());return s.executeUpdate()==1;}}public boolean updateStatus(Connection c,Long id,String st)throws SQLException{try(PreparedStatement s=c.prepareStatement("UPDATE BEDS SET STATUS=?,UPDATED_AT=CURRENT_TIMESTAMP WHERE BED_ID=?")){s.setString(1,st);s.setLong(2,id);return s.executeUpdate()==1;}}public boolean existsByRoomAndBedNumber(Long room,String n)throws SQLException{return duplicate(room,n,null);}public boolean existsByRoomAndBedNumberExcludingId(Long room,String n,Long id)throws SQLException{return duplicate(room,n,id);}private boolean duplicate(Long room,String n,Long id)throws SQLException{try(Connection c=DatabaseConnectionManager.getConnection();PreparedStatement s=c.prepareStatement("SELECT 1 FROM BEDS WHERE ROOM_ID=? AND BED_NUMBER=?"+(id==null?"":" AND BED_ID<>?")+" FETCH FIRST 1 ROW ONLY")){s.setLong(1,room);s.setString(2,n);if(id!=null)s.setLong(3,id);try(ResultSet r=s.executeQuery()){return r.next();}}}public boolean isAvailable(Long id)throws SQLException{return findById(id).filter(b->"AVAILABLE".equals(b.getStatus())).isPresent();}private void pair(PreparedStatement s,int i,Long v)throws SQLException{if(v==null){s.setNull(i,Types.NUMERIC);s.setNull(i+1,Types.NUMERIC);}else{s.setLong(i,v);s.setLong(i+1,v);}}private Bed map(ResultSet r)throws SQLException{Bed b=new Bed();b.setBedId(r.getLong("BED_ID"));b.setRoomId(r.getLong("ROOM_ID"));b.setBedNumber(r.getString("BED_NUMBER"));b.setRoomNumber(r.getString("ROOM_NUMBER"));b.setRoomType(r.getString("ROOM_TYPE"));b.setDailyRate(r.getBigDecimal("DAILY_RATE"));b.setStatus(r.getString("STATUS"));long a=r.getLong("CURRENT_ADMISSION_ID");b.setCurrentAdmissionId(r.wasNull()?null:a);long p=r.getLong("CURRENT_PATIENT_ID");b.setCurrentPatientId(r.wasNull()?null:p);b.setCurrentPatientName(r.getString("CURRENT_PATIENT_NAME"));return b;}}
